∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input},
  CT15.FullRankState S capability input rank → rank.value = CT15.targetRank S capability

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input},
  CT15.FullRankState S capability input rank → ∀ (coordinate : S.Coordinate), ¬S.TargetDependent input coordinate

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  (self : CT15.LedgerState S capability input full), self.entries = CT15.ledgerEntries S capability input

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  (self : CT15.LedgerState S capability input full), self.total = CT15.ledgerTotal S capability input

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  {ledger : CT15.LedgerState S capability input full},
  S.capacity input < ledger.total → CT15.C4Certificate S capability input ledger

∀ {P : Core.Problem} {S : CT15.Spec P} {capability : CT15.Capability S} {input : CT15.Input P}
  {rank : CT15.RankState S capability input} {full : CT15.FullRankState S capability input rank}
  {ledger : CT15.LedgerState S capability input full},
  ledger.total ≤ S.capacity input → CT15.FullRankLedgerResidual S capability input ledger
